using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed))
{
    Console.WriteLine($"TryGetTypeInfo succeeded for Person: {probed!.Type.Name}");
}

// Use a resolver that knows about nothing to show the "not available" path
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty composite
};

if (!limited.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("TryGetTypeInfo correctly returned false — no metadata available.");
}

record Person(string Name, int Age);

